Beispiele 1: Allgemeine Verwendung der Klasse:
             \code
             public readFromDb(List[EnOberflaeche] oberflaechen)
             {
                 //Verbindungsdaten
                 EnConnectionData conData = new EnConnectionData();
                 conData.DatabaseTyp = EnConnectionData.DbTyp.Access;
                 conData.Datenbank = @"d:\test.accdb"; 

                 //Datenbank Verbindung
                 DbConnection dbCon = new DbConnection(conData);

                 //Sql Zugriffsobjekt
                 DbSqlBase dbSql = new DbSqlBase(dbCon);

                 int maxSpalten = 3;
                 string sql = "Select Id, BezeichnungDeutsch ,Ral from Beschichtungen where Verfuegbar=True order by Id";

                 //Sql Statement ausführen (Die Datenbank wird automatisch geöffnet, falls sie noch nicht geöffnet war)
                 EnMatrix matrix = new EnMatrix();
                 if (!dbSql.executeSql(sql, matrix))
                     return false;

                 //Anzahl der Spalten im Sql Statement prüfen
                 if (matrix.MaxColumn != maxSpalten)
                 {
                     Errorliste.addErrorId(DbError.errFalscheAnzSpalten.ToString());
                     return false;
                 }

                 try
                 {
                     //Ergebnis in Liste schreiben
                     for (int count = 0; count (kleiner als) matrix.MaxRow; count++)
                     {
                         int id = (int)matrix.getAt(count, 0);
                         string bezeichnung = (string)matrix.getAt(count, 1);
                         int ral = (int)matrix.getAt(count, 2);

                         EnOberflaeche obfl = new EnOberflaeche(id, bezeichnung, ral);
                         oberflaechen.Add(obfl);
                     }
                 }
                 catch (Exception ex)
                 {
                     this.Errorliste.addError(ex.Message);
                     return false;
                 }
                 finally
                 {
                     dbCon.closeDb();
                 }	

                 return true;
             }
             \endcode

             Beispiel 2: Klasse ableiten
             \code
             public class DbProjekt : DbSqlBase
             {
                 //Tabellenname
                 string tabname = "Projekt";

                 //Key Spalten
                 string spalteBezProjektNr = "Nummer";
                 string spalteBezProjektAbschnittsNr = "AbschnittsNr";

                 public DbProjekt(MxLib.Db.DbConnection conectionData)
            		: base(conectionData)
                 {
                 }

                 List[string] getSpalten()
                 {
                     List[string] sp = new List[string]();
                     sp.Add(spalteBezProjektNr);
                     sp.Add(spalteBezProjektAbschnittsNr);
                     sp.Add("Bezeichnung");
                     sp.Add("Leiter");

                     return sp;
                 }

                 public bool save(EnProjekt projekt)
                 {
                     bool result = true;                     

                     //Filter setzen
                     EnSqlFilter filter = new EnSqlFilter();
                     filter.addFilter(spalteBezProjektNr, projekt.Nummer);
                     filter.addFilter(spalteBezProjektAbschnittsNr, projekt.AbschnittsNr);

                     //prüfen ob der Datensatz schon existiert
                     long count = countRows(tabname, filter); 

                     List[object] values = new List[object]();
                     values.Add(projekt.Nummer);
                     values.Add(projekt.AbschnittsNr);
                     values.Add(projekt.Bezeichnung);
                     values.Add(projekt.Leiter);

                     int changedRow = 0;
                     if (count == 1)            
                        result = updateTable(tabname, getSpalten(), values, filter, ref changedRow);
                     else if (count == 0)
                        result = insertInto(tabname, getSpalten(), values);
                     else
                        throw new MxException(null, "err_freigabe_zuvieleDatensatze");

                    return result; 
                 }
             }
             \endcode
